import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { booksAPI, finesAPI, libraryCardsAPI, issuesAPI } from '../services/api';

// ── Reusable stat card ───────────────────────────────────────
const StatCard = ({ icon, color, value, label }) => (
  <div className="col-sm-6 col-lg-3">
    <div className="stat-card">
      <div className={`stat-icon ${color}`}><i className={`bi ${icon}`}></i></div>
      <div>
        <div className="stat-value">{value}</div>
        <div className="stat-label">{label}</div>
      </div>
    </div>
  </div>
);

// ── Quick-action button ──────────────────────────────────────
const QuickAction = ({ to, icon, label, color }) => (
  <Link to={to} className="lib-card p-3 d-flex align-items-center gap-3 text-decoration-none"
    style={{ color: 'var(--text-main)', transition: 'transform .2s' }}
    onMouseEnter={e => e.currentTarget.style.transform='translateY(-2px)'}
    onMouseLeave={e => e.currentTarget.style.transform='translateY(0)'}>
    <div className={`stat-icon ${color}`} style={{ flexShrink: 0 }}>
      <i className={`bi ${icon}`}></i>
    </div>
    <span style={{ fontWeight: 500, fontSize: '.92rem' }}>{label}</span>
    <i className="bi bi-chevron-right ms-auto text-muted" style={{ fontSize: '.75rem' }}></i>
  </Link>
);

// ──────────────────────────────────────────────────────────────
const DashboardPage = () => {
  const { currentUser } = useAuth();
  const role = currentUser?.role;

  const [loading, setLoading] = useState(true);
  const [data, setData] = useState({
    books: [],
    fines: [],
    requests: [],
    myCard: null,
    issues: []
  });

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        const booksReq = booksAPI.getAll();

        if (role === 'Student') {
          const finesReq = finesAPI.getMyFines();
          const cardReq = libraryCardsAPI.getMyCard().catch((err) => {
            if (err.statusCode === 404) return { data: { data: null } };
            throw err;
          });
          const issuesReq = issuesAPI.getAll();

          const [bRes, fRes, cRes, iRes] = await Promise.all([booksReq, finesReq, cardReq, issuesReq]);

          setData({
            books: bRes.data?.data || [],
            fines: fRes.data?.data || [],
            myCard: cRes.data?.data || null,
            issues: iRes.data?.data || []
          });
        } else {
          const finesReq = finesAPI.getAll();
          const cardsReq = libraryCardsAPI.getAll();
          const issuesReq = issuesAPI.getAll();

          const [bRes, fRes, cRes, iRes] = await Promise.all([booksReq, finesReq, cardsReq, issuesReq]);

          setData({
            books: bRes.data?.data || [],
            fines: fRes.data?.data || [],
            requests: cRes.data?.data || [],
            issues: iRes.data?.data || []
          });
        }
      } catch (err) {
        console.error("Dashboard fetch error", err);
      } finally {
        setLoading(false);
      }
    };
    if (role) fetchDashboardData();
  }, [role]);

  if (loading) return <div className="text-center py-5"><div className="spinner-border text-primary text-center"></div></div>;

  const finesArray = Array.isArray(data.fines) ? data.fines : [];
  const booksArray = Array.isArray(data.books) ? data.books : [];
  const issuesArray = Array.isArray(data.issues) ? data.issues : [];
  const requestsArray = Array.isArray(data.requests) ? data.requests : [];

  const unpaidFines = finesArray.filter(f => (f.status || '').toLowerCase() === 'unpaid');
  const availableBooks = booksArray.filter(b => b.availableCopies > 0).length;
  const activeIssues = issuesArray.filter(i => !i.returnDate).length;
  const pendingRequests = requestsArray.filter(r => (r.status || '').toLowerCase() === 'pending').length;
  const approvedRequests = requestsArray.filter(r => (r.status || '').toLowerCase() === 'approved').length;

  const handleApprove = async (id) => {
    try {
      await libraryCardsAPI.approve(id);
      // Refresh data
      window.location.reload();
    } catch (err) {
      alert(err.message || 'Approval failed');
    }
  };

  const handleReject = async (id) => {
    const reason = prompt('Enter rejection reason:');
    if (!reason) return;
    try {
      await libraryCardsAPI.reject(id, reason);
      // Refresh data
      window.location.reload();
    } catch (err) {
      alert(err.message || 'Rejection failed');
    }
  };

  return (
    <div className="page-wrapper">
      <div className="container">
        {/* ── Header ─────────────────────────────────────── */}
        <div className="d-flex align-items-center gap-3 mb-4 flex-wrap">
          <div style={{ width: 54, height: 54, borderRadius: '50%', background: 'var(--primary)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <i className="bi bi-person-fill text-white" style={{ fontSize: '1.4rem' }}></i>
          </div>
          <div>
            <h2 className="section-title mb-0">Hello, {currentUser?.name?.split(' ')[0]}! 👋</h2>
            <span className={`badge-role badge-${role?.toLowerCase()}`}>{role} Dashboard</span>
          </div>
        </div>

        {/* ══════════ STUDENT DASHBOARD ══════════ */}
        {role === 'Student' && (
          <>
            {/* Stats */}
            <div className="row g-3 mb-4">
              <StatCard icon="bi-journals"          color="red"   value={availableBooks}             label="Books Available" />
              <StatCard icon="bi-credit-card"       color="gold"  value={data.myCard ? 1 : 0} label="Library Card" />
              <StatCard icon="bi-currency-rupee"    color="green" value={'₹' + unpaidFines.reduce((s,f) => s + (f.amount || f.fineAmount || 0), 0)} label="Unpaid Fines" />
              <StatCard icon="bi-check-circle"      color="blue"  value={activeIssues} label="Active Books Issued" />
            </div>

            {/* Quick actions */}
            <div className="mb-4">
              <h5 className="section-title mb-2" style={{ fontSize: '1.1rem' }}>Quick Actions</h5>
              <div className="row g-3">
                <div className="col-md-4"><QuickAction to="/books"        icon="bi-search"       color="red"   label="Browse Books" /></div>
                <div className="col-md-4"><QuickAction to="/request-card" icon="bi-credit-card"  color="gold"  label="Library Card Status" /></div>
                <div className="col-md-4"><QuickAction to="/fines"        icon="bi-currency-rupee" color="green" label="View My Fines" /></div>
              </div>
            </div>

            {/* My Issues */}
            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-list-check me-2"></i>My Currently Issued Books</h5>
              </div>
              <div className="table-responsive p-0">
                <table className="lib-table">
                  <thead><tr><th>#</th><th>Book</th><th>Issue Date</th><th>Due Date</th></tr></thead>
                  <tbody>
                    {issuesArray.filter(r => !r.returnDate).length === 0 ? (
                      <tr><td colSpan="4" className="text-center text-muted py-3">No active issued books. <Link to="/books">Browse books</Link></td></tr>
                    ) : (
                      issuesArray.filter(r => !r.returnDate).map((r, i) => (
                        <tr key={r._id}>
                          <td>{i+1}</td>
                          <td>{r.book?.title}</td>
                          <td>{r.issueDate ? new Date(r.issueDate).toLocaleDateString() : 'N/A'}</td>
                          <td style={{ color: 'var(--danger)' }}>{r.dueDate ? new Date(r.dueDate).toLocaleDateString() : 'N/A'}</td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

        {/* ══════════ LIBRARIAN DASHBOARD ══════════ */}
        {role === 'Librarian' && (
          <>
            <div className="row g-3 mb-4">
              <StatCard icon="bi-journals"       color="red"   value={booksArray.length}    label="Total Books" />
              <StatCard icon="bi-clock-history"  color="gold"  value={pendingRequests} label="Pending Cards" />
              <StatCard icon="bi-check-circle"   color="green" value={approvedRequests} label="Approved Cards" />
              <StatCard icon="bi-exclamation-triangle" color="blue" value={'₹' + unpaidFines.reduce((s,f) => s + (f.amount || f.fineAmount || 0), 0)} label="Unpaid Fines" />
            </div>

            <div className="row g-3 mb-4">
              <div className="col-md-6"><QuickAction to="/books" icon="bi-journals" color="red" label="Manage Book Catalog" /></div>
              <div className="col-md-6"><QuickAction to="/fines" icon="bi-currency-rupee" color="gold" label="Fine Records" /></div>
            </div>

            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-inbox me-2"></i>Library Card Applications</h5>
              </div>
              <div className="table-responsive">
                <table className="lib-table">
                  <thead><tr><th>#</th><th>Student</th><th>Course</th><th>Branch</th><th>Date</th><th>Status</th><th>Action</th></tr></thead>
                  <tbody>
                    {requestsArray.length === 0 ? (
                      <tr><td colSpan="7" className="text-center text-muted py-3">No applications found</td></tr>
                    ) : (
                      requestsArray.map((r, i) => (
                        <tr key={r._id}>
                          <td>{i+1}</td>
                          <td>{r.student?.name}</td>
                          <td>{r.course || 'N/A'}</td>
                          <td>{r.branch || 'N/A'}</td>
                          <td>{new Date(r.createdAt).toLocaleDateString()}</td>
                          <td><span className={`badge-role badge-${(r.status || '').replace(/\s+/g, '-')}`}>{r.status}</span></td>
                          <td>
                            {r.status === 'pending' && (
                              <>
                                <button className="btn btn-sm btn-lib-primary me-1" onClick={() => handleApprove(r._id)}>Approve</button>
                                <button className="btn btn-sm btn-lib-secondary" onClick={() => handleReject(r._id)}>Reject</button>
                              </>
                            )}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

        {/* ══════════ ADMIN DASHBOARD ══════════ */}
        {role === 'Admin' && (
          <>
            <div className="row g-3 mb-4">
              <StatCard icon="bi-people"         color="red"   value="Admin View"                    label="System User" />
              <StatCard icon="bi-journals"       color="gold"  value={booksArray.length}   label="Total Books" />
              <StatCard icon="bi-credit-card"    color="green" value={requestsArray.length}      label="Total Cards" />
              <StatCard icon="bi-currency-rupee" color="blue"  value={`₹${unpaidFines.reduce((s,f)=>s+(f.amount || f.fineAmount || 0),0)}`} label="Pending Fines" />
            </div>

            <div className="row g-3 mb-4">
              <div className="col-md-4"><QuickAction to="/books" icon="bi-journals"       color="red"   label="Manage Books" /></div>
              <div className="col-md-4"><QuickAction to="/fines" icon="bi-currency-rupee" color="gold"  label="Fine Management" /></div>
              <div className="col-md-4"><QuickAction to="/request-card" icon="bi-credit-card" color="green" label="Final Card Approvals" /></div>
            </div>

            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-shield-check me-2"></i>Final Approval Required (Admin)</h5>
              </div>
              <div className="table-responsive">
                <table className="lib-table">
                  <thead><tr><th>#</th><th>Student</th><th>Status</th><th>Date</th><th>Action</th></tr></thead>
                  <tbody>
                    {requestsArray.filter(r => r.status === 'approved by librarian').length === 0 ? (
                      <tr><td colSpan="5" className="text-center text-muted py-3">No cards waiting for final approval</td></tr>
                    ) : (
                      requestsArray.filter(r => r.status === 'approved by librarian').map((r, i) => (
                        <tr key={r._id}>
                          <td>{i+1}</td>
                          <td>{r.student?.name}</td>
                          <td><span className="badge-role badge-pending">Approved by Librarian</span></td>
                          <td>{new Date(r.createdAt).toLocaleDateString()}</td>
                          <td>
                            <button className="btn btn-sm btn-lib-primary me-1" onClick={() => handleApprove(r._id)}>Final Approve</button>
                            <button className="btn btn-sm btn-lib-secondary" onClick={() => handleReject(r._id)}>Final Reject</button>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default DashboardPage;
